class Notification:
    recipient: str
    subject: str
    body: str
    channel: str = "email"


class NotificationService:
    """Dispatches notifications via multiple channels."""

    def __init__(self, smtp_host: str, sms_gateway: str):
        self._smtp_host = smtp_host
        self._sms_gateway = sms_gateway
        self._sent_count = 0

    def send(self, notification: Notification) -> bool:
        if notification.channel == "email":
            return self._send_email(notification)
        elif notification.channel == "sms":
            return self._send_sms(notification)
        else:
            logger.warning("Unknown channel: %s", notification.channel)
            return False

    def _send_email(self, notification: Notification) -> bool:
        logger.info("Sending email to %s via %s", notification.recipient, self._smtp_host)
        self._sent_count += 1
        return True

    def _send_sms(self, notification: Notification) -> bool:
        logger.info("Sending SMS to %s via %s", notification.recipient, self._sms_gateway)
        self._sent_count += 1
        return True

