import json
import logging
from pathlib import Path
from typing import Any

logger = logging.getLogger(__name__)


class ConfigLoader:
    """Loads and merges layered configuration files."""

    def __init__(self, config_dir: Path):
        self._config_dir = config_dir
        self._cache: dict[str, Any] = {}

    def load(self, env: str = "production") -> dict[str, Any]:
        base = self._read_file("base.json")
        override = self._read_file(f"{env}.json")
        merged = {**base, **override}
        self._cache[env] = merged
        logger.info("Loaded config for env=%s with %d keys", env, len(merged))
        return merged

    def _read_file(self, filename: str) -> dict[str, Any]:
        path = self._config_dir / filename
        if not path.exists():
            logger.warning("Config file not found: %s", path)
            return {}
        with open(path) as fh:
            return json.load(fh)

    def get_cached(self, env: str) -> dict[str, Any]:
        return self._cache.get(env, {})

