def retry_on_exception(max_retries: int = 3, delay: float = 1.0) -> Callable:
    """Decorator that retries a function on any exception."""
    def decorator(func: Callable) -> Callable:
        @wraps(func)
        def wrapper(*args: Any, **kwargs: Any) -> Any:
            last_exc = None
            for attempt in range(max_retries):
                try:
                    return func(*args, **kwargs)
                except Exception as exc:
                    last_exc = exc
                    logger.warning("Attempt %d/%d for %s failed: %s", attempt + 1, max_retries, func.__name__, exc)
                    time.sleep(delay)
            raise last_exc
        return wrapper
    return decorator

