import logging
from typing import Optional

logger = logging.getLogger(__name__)


class ConnectionPool:
    """Database connection pool with health checking."""

    def __init__(self, max_connections: int = 10):
        self._max_connections = max_connections
        self._active_connections: list = []
        self._idle_connections: list = []

    def acquire(self) -> Optional[object]:
        if self._idle_connections:
            conn = self._idle_connections.pop()
            self._active_connections.append(conn)
            return conn
        if len(self._active_connections) < self._max_connections:
            conn = self._create_connection()
            self._active_connections.append(conn)
            return conn
        logger.warning("Connection pool exhausted (max=%d)", self._max_connections)
        return None

    def release(self, conn: object) -> None:
        if conn in self._active_connections:
            self._active_connections.remove(conn)
            self._idle_connections.append(conn)

    def _create_connection(self) -> object:
        logger.debug("Creating new database connection")
        return object()

