import hashlib
import secrets
import logging
from typing import Optional
from datetime import datetime, timedelta, timezone

logger = logging.getLogger(__name__)


class TokenManager:
    def __init__(self, secret: str, token_ttl: int = 3600):
        self._secret = secret
        self._token_ttl = token_ttl
        self._store: dict[str, dict] = {}

    def generate_token(self, user_id: str) -> str:
        raw = secrets.token_urlsafe(32)
        hashed = hashlib.sha256(f"{raw}{self._secret}".encode()).hexdigest()
        self._store[hashed] = {
            "user_id": user_id,
            "expires": datetime.now(timezone.utc) + timedelta(seconds=self._token_ttl),
        }
        return raw

    def verify_token(self, token: str):
        hashed = hashlib.sha256(f"{token}{self._secret}".encode()).hexdigest()
        entry = self._store.get(hashed)
        if entry is None:
            return None
        if entry["expires"] < datetime.now(timezone.utc):
            del self._store[hashed]
            return None
        return entry["user_id"]

