import json
import gzip
import logging
from typing import Any

logger = logging.getLogger(__name__)


class MessageSerializer:
    def __init__(self, compress: bool = False):
        self._compress = compress

    def serialize(self, payload: dict[str, Any]) -> bytes:
        json_bytes = json.dumps(payload, separators=(",", ":")).encode("utf-8")
        if self._compress:
            return gzip.compress(json_bytes)
        return json_bytes

    def deserialize(self, raw: bytes) -> dict[str, Any]:
        if self._compress:
            raw = gzip.decompress(raw)
        return json.loads(raw)

    def serialize_batch(self, messages: list[dict[str, Any]]) -> bytes:
        combined = [self.serialize(payload) for payload in messages]
        length_prefixed = b"".join(
            len(chunk).to_bytes(4, "big") + chunk for chunk in combined
        )
        return length_prefixed

