import logging
import time
from dataclasses import dataclass, field
from typing import Callable, Dict, List, Optional

logger = logging.getLogger(__name__)


@dataclass
class HealthCheck:
    name: str
    check_fn: Callable[[], bool]
    interval_seconds: float = 30.0
    timeout_seconds: float = 5.0
    last_status: Optional[bool] = None
    last_check_time: Optional[float] = None


@dataclass
class HealthReport:
    service_name: str
    checks: Dict[str, bool] = field(default_factory=dict)
    timestamp: float = 0.0

    @property
    def is_healthy(self) -> bool:
        return all(self.checks.values())


class HealthCheckService:
    def __init__(self, service_name: str, max_workers: int = 4):
        self._service_name = service_name
        self._checks: List[HealthCheck] = []
        self._max_workers = max_workers

    def register(self, check: HealthCheck) -> None:
        self._checks.append(check)
        logger.info("Registered health check: %s", check.name)

    def run_all(self) -> HealthReport:
        from concurrent.futures import ThreadPoolExecutor, as_completed

        report = HealthReport(service_name=self._service_name, timestamp=time.time())
        with ThreadPoolExecutor(max_workers=self._max_workers) as executor:
            future_to_check = {
                executor.submit(self._execute_check, check): check
                for check in self._checks
            }
            for future in as_completed(future_to_check):
                check = future_to_check[future]
                try:
                    report.checks[check.name] = future.result()
                except Exception:
                    report.checks[check.name] = False
        return report

    def _execute_check(self, check: HealthCheck) -> bool:
        try:
            result = check.check_fn()
            check.last_status = result
            check.last_check_time = time.time()
            return result
        except Exception as exc:
            logger.error("Health check %s failed: %s", check.name, exc)
            return False

