from dataclasses import dataclass
from typing import Dict, List, Optional, Tuple

logger = logging.getLogger(__name__)

DEFAULT_TTL = 300.0  # 5 minutes


@dataclass
class DNSRecord:
    hostname: str
    addresses: List[str]
    ttl: float
    cached_at: float

    @property
    def is_expired(self) -> bool:
        return (time.monotonic() - self.cached_at) > self.ttl


class DNSCache:
    def __init__(self, default_ttl: float = DEFAULT_TTL):
        self._cache: Dict[str, DNSRecord] = {}
        self._default_ttl = default_ttl
        self._hits = 0
        self._misses = 0

    def lookup(self, hostname: str) -> Optional[List[str]]:

        record = self._cache.get(hostname)
        if record is None:
            self._misses += 1
            return None
        if record.is_expired:
            del self._cache[hostname]
            self._misses += 1
            return None
        self._hits += 1
        return record.addresses

    def store(self, hostname: str, addresses: List[str], ttl: Optional[float] = None) -> None:
        self._cache[hostname] = DNSRecord(
            hostname=hostname,
            addresses=addresses,
            ttl=ttl or self._default_ttl,
            cached_at=time.monotonic(),
        )

    def invalidate(self, hostname: str) -> bool:
        return self._cache.pop(hostname, None) is not None

    def clear(self) -> None:
        self._cache.clear()
        self._hits = 0
        self._misses = 0

    @property
    def hit_rate(self) -> float:
        total = self._hits + self._misses
        return self._hits / total if total > 0 else 0.0

