from contextlib import contextmanager
from typing import Any, Generator

logger = logging.getLogger(__name__)


class TransactionManager:
    """Manages database transactions with automatic rollback on failure."""

    def __init__(self, connection: Any):
        self._conn = connection
        self._savepoint_counter = 0

    @contextmanager
    def transaction(self) -> Generator[Any, None, None]:
        self._conn.execute("BEGIN")
        try:
            yield self._conn
            self._conn.execute("COMMIT")
            logger.info("Transaction committed")
        except Exception as exc:
            self._conn.execute("ROLLBACK")
            logger.error("Transaction rolled back: %s", exc)
            raise

    @contextmanager
    def savepoint(self, name: str = "") -> Generator[Any, None, None]:
        self._savepoint_counter += 1
        sp_name = name or f"sp_{self._savepoint_counter}"
        self._conn.execute(f"SAVEPOINT {sp_name}")
        try:
            yield self._conn
            self._conn.execute(f"RELEASE SAVEPOINT {sp_name}")
        except Exception:
            self._conn.execute(f"ROLLBACK TO SAVEPOINT {sp_name}")
