import logging
from collections import defaultdict
from dataclasses import dataclass, field
from typing import Any, Callable, Dict, List, Set

logger = logging.getLogger(__name__)


@dataclass
class Message:
    topic: str
    payload: Any
    headers: Dict[str, str] = field(default_factory=dict)


class MessageBroker:
    """In-process pub/sub message broker."""

    def __init__(self) -> None:
        self._subscribers: Dict[str, List[Callable[[Message], None]]] = defaultdict(list)
        self._dead_letter: List[Message] = []

    def subscribe(self, topic: str, handler: Callable[[Message], None]) -> None:
        self._subscribers[topic].append(handler)
        logger.info("Subscriber added for topic '%s'", topic)

    def publish(self, message: Message) -> int:
        handlers = self._subscribers.get(message.topic, [])
        if not handlers:
            self._dead_letter.append(message)
            logger.warning("No subscribers for topic '%s', sent to dead letter", message.topic)
            return 0
        delivered = 0
        for handler in handlers:
            try:
                handler(message)
                delivered += 1
            except Exception as exc:
                logger.error("Handler failed for topic '%s': %s", message.topic, exc)
        return delivered

    @property
    def dead_letter_count(self) -> int:
        return len(self._dead_letter)

    def get_topics(self) -> Set[str]:
        return set(self._subscribers.keys())

