        return self.priority < other.priority


class WorkQueue:
    def __init__(self, max_size: int = 0):
        self._queue: queue.PriorityQueue[WorkItem] = queue.PriorityQueue(maxsize=max_size)
        self._processed = 0
        self._lock = threading.Lock()

    def enqueue(self, item: WorkItem) -> None:
        self._queue.put(item)
        logger.debug("Enqueued item %s (priority=%d)", item.item_id, item.priority)

