import logging
from dataclasses import dataclass
from typing import Any, List, Optional

logger = logging.getLogger(__name__)


@dataclass
class SchemaMigration:
    version: int
    name: str
    up_sql: str
    down_sql: str


class SchemaMigrator:
    def __init__(self, connection: Any):
        self._conn = connection
        self._current_version = 0

    def apply(self, migration: SchemaMigration) -> bool:
        if migration.version <= self._current_version:
            logger.info("Migration %s already applied", migration.name)
            return False
        try:
            self._conn.execute("BEGIN")
            self._conn.execute(migration.up_sql)
            self._current_version = migration.version
            self._conn.execute("COMMIT")
            logger.info("Applied migration %s (v%d)", migration.name, migration.version)
            return True
        except Exception as exc:
            self._conn.execute("ROLLBACK")
            logger.error("Migration %s failed: %s", migration.name, exc)
            raise

    def apply_all(self, migrations: List[SchemaMigration]) -> int:
        applied = 0
        sorted_migrations = sorted(migrations, key=lambda m: m.version)
        for migration in sorted_migrations:
            if self.apply(migration):
                applied += 1
        return applied

    def rollback_to(self, target_version: int, migrations: List[SchemaMigration]) -> int:
        rolled_back = 0
        desc_migrations = sorted(
            [m for m in migrations if m.version > target_version],
            key=lambda m: m.version,
            reverse=True,
        )
        for migration in desc_migrations:
            if migration.version <= self._current_version:
                try:
                    self._conn.execute("BEGIN")
                    self._conn.execute(migration.down_sql)
                    self._current_version = migration.version - 1
                    self._conn.execute("COMMIT")
                    rolled_back += 1
                except Exception as exc:
                    self._conn.execute("ROLLBACK")
                    logger.error(
                        "Rollback of %s failed: %s",
                    )
                    raise
        return rolled_back

    @property
    def current_version(self) -> int:
        return self._current_version

