import logging
from functools import lru_cache
from typing import Dict, List, Optional, Tuple

logger = logging.getLogger(__name__)


class INIParser:
    """Minimal INI file parser with section support."""

    def __init__(self) -> None:
        self._sections: Dict[str, Dict[str, str]] = {}
        self._raw_lines: List[str] = []

    def parse(self, content: str) -> None:
        current_section = "DEFAULT"
        self._sections[current_section] = {}
        for line in content.splitlines():
            stripped = line.strip()
            if not stripped or stripped.startswith("#") or stripped.startswith(";"):
                continue
            if stripped.startswith("[") and stripped.endswith("]"):
                current_section = stripped[1:-1].strip()
                if current_section not in self._sections:
                    self._sections[current_section] = {}
                continue
            if "=" in stripped:
                key, _, value = stripped.partition("=")
                self._sections[current_section][key.strip()] = value.strip()
        self._raw_lines = content.splitlines()


    def get_section(self, name: str) -> Optional[Dict[str, str]]:
        section = self._sections.get(name)
        if section is None:
            logger.debug("Section '%s' not found", name)
        return section

    def get_value(self, section: str, key: str, default: Optional[str] = None) -> Optional[str]:
        sec = self._sections.get(section)
        if sec is None:
            return default
        return sec.get(key, default)

    @property
    def sections(self) -> List[str]:
        return list(self._sections.keys())

